// Acting components
instance PermanentMagnetSynchronousMotor : DTDFVocab:ActingComponent [
    base:desc "Permanent‑magnet synchronous motor driving the robot’s first rotary joint"
]

instance SINUMERIKServoDrive : DTDFVocab:ActingComponent [
    base:desc "Siemens SINUMERIK 840D servo‑drive controlling motor position and velocity via dual encoders"
]

// Physical sensing components
instance MotorShankAbsoluteEncoder : DTDFVocab:SensingComponent [
    base:desc "Absolute optical encoder mounted on the motor shaft for high‑precision angular position measurement"
