]

instance GearboxEncoderTrace : DTDFVocab:Data [
    base:desc "Stream of gearbox encoder angle values collected over time"
    DTDFVocab:fromData GearboxEncoderMQTT
    DTDFVocab:inputTo MQTT_MessagingBroker, MATLABSimulink_CoSimulation
]

